using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Preserve existing property name for compatibility with stored documents.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Preserve existing id format so existing documents remain addressable.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined via EF Core.
            // HasIndex() now throws at runtime in EF 9. Removed.
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change 4: EF 9 uses sync-over-async detection.
        // Use async APIs instead (see SyncJob.cs).
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

